var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흑, 흐윽……!","JPN":"うっ、ううっ……！","ENG":"*Sob* *Sniffle*","TWN":"嗚嗚，嗚嗚……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"죄송해요, 죄송해요……! 저 때문에 당신이……!","JPN":"ごめんなさ、うっ、ごめんなさい……！　私のせいであなたが……！","ENG":"I'm sorry, I'm sorry...! Because of me, you...!","TWN":"對不起，對不起……！因為我害得你……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신은……. 저를 지켜주려다가……!","JPN":"あなたは……私を庇おうとして……！","ENG":"While... trying to protect me...!","TWN":"為了保護我……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"여기는……?","JPN":"ここは……？","ENG":"What is this place?","TWN":"這裡是……？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애, 애버라인! 정신이 드세요?","JPN":"あ、アバーライン！　気がつきました？","ENG":"A-Abberline! Are you okay?","TWN":"艾，艾伯林！你醒了嗎？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군……. 마물의 공격을 피해, 숲 속에 있던 폭포 아래로 떨어지고 말았나……?","JPN":"そうか……魔物から逃げようとして、森の中にあった滝の下に落ちてしまったのか……？","ENG":"I see... So we fell down the waterfall in the forest while trying to avoid the monster's attack...","TWN":"原來如此……為了躲避怪物的攻擊，掉到了森林裡的瀑布下嗎……？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 자네가 나를 감싸서……","JPN":"ということは、君が私を庇って……","ENG":"Then you protected me–","TWN":"那麼是你救了我……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"크윽!","JPN":"うっ！","ENG":"Urgh!","TWN":"咳！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 그만 말해요! 피가, 피가 많이 난다고요……!","JPN":"しゃ、喋っちゃダメ、アバーライン！　血が、出血がひどい……！","ENG":"Abberline, stop talking! You're... you're bleeding a lot...!","TWN":"艾伯林，別說了！血，血流得很多啊……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다행이야……. 덕분에 약간이나마 시간을 벌었군…….","JPN":"よかった……おかげで少しは時間を稼げたか。","ENG":"Thank goodness... We bought some time thanks to you...","TWN":"太好了……多虧如此，總算爭取到了一點時間……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 역시 내 눈은 틀리지 않았어…….","JPN":"ふふ、やはり私の目に狂いはなかったようだ……","ENG":"Haha, I knew my eyes are never wrong...","TWN":"呵呵，果然我的眼睛沒有看錯……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 내 훌륭한 파트너야.","JPN":"君は私の立派なパートナーだ。","ENG":"You're a great partner.","TWN":"你是我出色的搭檔。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제발! 왜 이런 상황에까지 웃는 건데요!","JPN":"やめてください！　どうしてこんな状況にまで笑ってるんですか！","ENG":"Come on! How are you laughing at this situation?!","TWN":"拜託！為什麼這種情況下你還在笑！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나는, 나는……!","JPN":"私、私は……！","ENG":"I... I...!","TWN":"我，我……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 당신이……!","JPN":"アバーライン、あなたが……！","ENG":"Abberline, you...!","TWN":"艾伯林，你……！"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 이제 더는 미룰 수 없겠지.","JPN":"そう、もうこれ以上は先延ばしできないな。","ENG":"Yes. I can't afford to delay it any longer.","TWN":"嗯，現在不能再拖了。"},"stage":{"bg":"SWANSONG_04","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완, 자네에게 전해야 할 말이 있네.","JPN":"スワン、君に話さないといけないことがある。","ENG":"Swan. There is something I should tell you.","TWN":"史旺，我有話要對你說。"},"stage":{"bg":"SWANSONG_04","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧 전하지 못했던 이 세계의 <color=#ffd34c>진실</color>이지.","JPN":"ずっと伝えられなかった、この世界の<color=#ffd34c>真実</color>だ。","ENG":"It's about the <color=#ffd34c>truth</color> of this world that hasn't been told.","TWN":"一直沒能告訴你的，這個世界的<color=#ffd34c>真相</color>。"},"stage":{"bg":"SWANSONG_04","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 진실이라고요……?","JPN":"この世界の真実……？","ENG":"The truth of this world...?","TWN":"這個世界的真相嗎……？"},"stage":{"bg":"SWANSONG_04","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"사, 사람들이 하늘로 끌려 올라가고 있어……!","JPN":"ひ、人が空に向かって浮き上がっている……！","ENG":"P-people are being dragged up into the sky...!","TWN":"人，人們被拉上了天空……！"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"위를 보지 마! 하늘의 눈과 마주치면 마물이 되어버린다고……!","JPN":"上を見るな！　空と目が合うと魔物になってしまう……！","ENG":"Don't look up! You make eye contact with the eye of the sky and you'll turn into a monster...!","TWN":"不要看上面！一旦與天空對視，就會變成怪物的……！"},"stage":{"bg":"MS_1203","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"과, 관절이 뒤틀려서…….","JPN":"か、関節が曲がって……","ENG":"M-my joints are twisting–","TWN":"你、你的關節在扭曲啊啊啊……"},"stage":{"bg":"MS_1203","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"으, 으아, 으아아아아아아아아악……!!","JPN":"う、うわ、うわああああああああ……！！","ENG":"A-AAAAAAAAGH...!!","TWN":"呃？呃啊，呃啊啊啊啊啊啊啊啊啊……！！"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕이시여. 당신의 권능이 이 세계의 거의 모든 인간을 절멸시켰습니다.","JPN":"王よ。あなたの権能がこの世界のほぼすべての人間を絶滅させました。","ENG":"My queen. Your power has almost wiped out the entire human population.","TWN":"王，你的權能幾乎滅絕了這個世界上的所有人類。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};